   198	        private static string RemoveMatchingBraces(string s)
   199	        {
   200	            var stack = new Stack<char>();
   201	            var count = 0;
   202	            foreach (var ch in s)
   203	            {
   204	                switch (ch)
   205	                {
   206	                    case '(':
   207	                        count += 1;
   208	                        stack.Push(ch);
   209	                        break;
   210	                    case ')':
   211	                        if (count == 0)
   212	                        {
   213	                            stack.Push(ch);
   214	                        }
   215	                        else
   216	                        {
   217	                            char popped;
   218	                            do
   219	                            {
   220	                                popped = stack.Pop();
   221	                            }
   222	                            while (popped != '(');
   223	                            count -= 1;
   224	                        }
   225	
   226	                        break;
   227	                    default:
   228	                        stack.Push(ch);
   229	                        break;
   230	                }
   231	            }
   232	
   233	            return string.Join(string.Empty, stack.Reverse());
   234	        }
   235	    }
