cat > "$WORK/Program.cs" <<'EOF'
using RevEng.Core.Abstractions.Metadata;
using RevEng.Core.Routines.Extensions;

static void Expect(bool condition, string message)
{
    if (!condition)
    {
        throw new InvalidOperationException(message);
    }
}

var citextResultType = PostgresNpgsqlTypeExtensions.GetClrType("citext", isNullable: true, objectName: "testcitextout");
Expect(citextResultType == typeof(string), $"citext result mapped to {citextResultType}, expected string");

var citextParameter = new ModuleParameter
{
    Name = "p_citext",
    StoreType = "citext",
    Nullable = true,
};
