private void RemoveUnsupportedRoutines(RoutineModel model, ModuleScaffolderOptions scaffolderOptions, List<string> errors)
{
    var unsupportedRoutines = new List<Routine>();

    foreach (var routine in model.Routines)
    {
        if (TryGetUnsupportedRoutineMessage(routine, scaffolderOptions, out var message))
        {
            errors.Add(message);
            unsupportedRoutines.Add(routine);
        }
    }

    foreach (var routine in unsupportedRoutines)
    {
        model.Routines.Remove(routine);
    }
}

private bool TryGetUnsupportedRoutineMessage(Routine routine, ModuleScaffolderOptions scaffolderOptions, out string message)
{
    foreach (var parameter in routine.Parameters)
    {
        try
        {
            typeMapper.GetClrType(parameter);
        }
        catch (ArgumentException ex)
        {
            message = $"Unable to scaffold {FormatRoutineName(routine)}: parameter '{parameter.Name}' has unsupported store type '{parameter.StoreType}'. {ex.Message}";
            return true;
        }

        if (scaffolderOptions.UseTypedTvpParameters && parameter.TvpColumns?.Count > 0)
        {
            foreach (var column in parameter.TvpColumns)
            {
                if (TryGetUnsupportedResultElementMessage(routine, column, "TVP column", out message))
                {
                    return true;
                }
            }
        }
    }

    if (string.IsNullOrEmpty(routine.MappedType))
    {
        foreach (var resultElement in routine.Results.SelectMany(r => r))
        {
            if (TryGetUnsupportedResultElementMessage(routine, resultElement, "result column", out message))
            {
                return true;
            }
        }
    }

    message = null;
    return false;
}

private bool TryGetUnsupportedResultElementMessage(Routine routine, ModuleResultElement resultElement, string elementType, out string message)
{
    try
    {
        typeMapper.GetClrType(resultElement);
    }
    catch (ArgumentException ex)
    {
        message = $"Unable to scaffold {FormatRoutineName(routine)}: {elementType} '{resultElement.Name}' has unsupported store type '{resultElement.StoreType}'. {ex.Message}";
        return true;
    }

    message = null;
    return false;
}

private static string FormatRoutineName(Routine routine)
{
    return $"\"{routine.Schema}\".\"{routine.Name}\"";
}

