#!/usr/bin/env bash
WORK=/tmp/efcpt-citext-repro
rm -rf "$WORK"
mkdir -p "$WORK"
cat > "$WORK/CitextRepro.csproj" <<'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
    <ImplicitUsings>enable</ImplicitUsings>
    <Nullable>enable</Nullable>
  </PropertyGroup>
  <ItemGroup>
    <ProjectReference Include="/workspace/EFCorePowerTools/src/Core/RevEng.Core.80/RevEng.Core.80.csproj" />
  </ItemGroup>
</Project>
EOF
cat > "$WORK/Program.cs" <<'EOF'
using Microsoft.EntityFrameworkCore.Design;
using Microsoft.Extensions.DependencyInjection;
using RevEng.Common;
using RevEng.Core;
using RevEng.Core.Abstractions;
using RevEng.Core.Abstractions.Metadata;
using RevEng.Core.Routines.Extensions;
using RevEng.Core.Routines.Procedures;

static void Expect(bool condition, string message)
{
    if (!condition)
    {
        throw new InvalidOperationException(message);
    }
}

var citextResultType = PostgresNpgsqlTypeExtensions.GetClrType("citext", isNullable: true, objectName: "testcitextout");
Expect(citextResultType == typeof(string), $"citext result mapped to {citextResultType}, expected string");

var citextParameter = new ModuleParameter
{
    Name = "p_citext",
    StoreType = "citext",
    Nullable = true,
};
var citextParameterType = citextParameter.ClrTypeFromNpgsqlParameter(asMethodParameter: true);
Expect(citextParameterType == typeof(string), $"citext parameter mapped to {citextParameterType}, expected string");
Expect(citextParameter.GetNpgsqlDbType().ToString() == "Citext", "citext should preserve NpgsqlDbType.Citext");

try
{
    PostgresNpgsqlTypeExtensions.GetClrType("refcursor", isNullable: true, objectName: "p_refcur");
    throw new InvalidOperationException("refcursor unexpectedly mapped successfully");
}
catch (ArgumentOutOfRangeException ex) when (ex.Message.Contains("storetype: refcursor", StringComparison.Ordinal) && ex.Message.Contains("objectName: p_refcur", StringComparison.Ordinal))
{
    Console.WriteLine("unsupported refcursor still reports store type and object name");
}

var serviceErrors = new List<string>();
var services = new ServiceCollection();
services.AddEfpt(new ReverseEngineerCommandOptions { DatabaseType = DatabaseType.Npgsql }, serviceErrors, new List<string>(), new List<string>());
using var provider = services.BuildServiceProvider();
var code = provider.GetRequiredService<ICSharpHelper>();
var scaffolder = new PostgresStoredProcedureScaffolder(code, new PostgresClrTypeMapper());
var model = new RoutineModel
{
    Errors = new List<string>(),
    Routines = new List<Routine>
    {
        new Procedure
        {
            Schema = "dbo",
            Name = "testrefcursor",
            HasValidResultSet = true,
            Results = new List<List<ModuleResultElement>> { new() },
            Parameters = new List<ModuleParameter>
            {
                new() { Name = "p_refcur", StoreType = "refcursor", Nullable = true },
            },
        },
        new Procedure
        {
            Schema = "dbo",
            Name = "testtext",
            HasValidResultSet = true,
            Results = new List<List<ModuleResultElement>> { new() },
            Parameters = new List<ModuleParameter>
            {
                new() { Name = "p_text", StoreType = "text", Nullable = true },
            },
        },
    },
};
var scaffoldErrors = new List<string>();
var scaffolded = scaffolder.ScaffoldModel(model, new ModuleScaffolderOptions
{
    ContextDir = ".",
    ContextName = "PGContext",
    ContextNamespace = "Repro",
    ModelNamespace = "Repro",
    UseAsyncCalls = true,
    UsePascalIdentifiers = false,
}, new List<string>(), ref scaffoldErrors);
var combinedCode = string.Join("\n", scaffolded.AdditionalFiles.Select(f => f.Code).Append(scaffolded.ContextFile.Code));
Expect(scaffoldErrors.Any(e => e.Contains("Unable to scaffold \"dbo\".\"testrefcursor\": parameter 'p_refcur' has unsupported store type 'refcursor'", StringComparison.Ordinal)), "unsupported routine error was not reported clearly");
Expect(!combinedCode.Contains("testrefcursor", StringComparison.Ordinal), "unsupported routine should be omitted from generated code");
Expect(combinedCode.Contains("testtextAsync", StringComparison.Ordinal), "supported routine should still be generated");

Console.WriteLine("citext mapping and unsupported routine skip reproduction passed");
EOF
cd /tmp
dotnet run --project "$WORK/CitextRepro.csproj" --verbosity quiet
SH
chmod +x /tmp/efcpt-citext-repro.sh
/tmp/efcpt-citext-repro.sh

