+        private bool TryGetUnsupportedRoutineMessage(Routine routine, ModuleScaffolderOptions scaffolderOptions, out string message)
+        {
+            foreach (var parameter in routine.Parameters)
+            {
+                try
+                {
+                    typeMapper.GetClrType(parameter);
+                }
+                catch (ArgumentException ex)
+                {
+                    message = $"Unable to scaffold {FormatRoutineName(routine)}: parameter '{parameter.Name}' has unsupported store type '{parameter.StoreType}'. {ex.Message}";
